'use client';

import React, { useState } from 'react'; // Tambahkan useState
import { AnimatePresence } from 'framer-motion'; // Tambahkan AnimatePresence
import Header from './Header';
import Footer from './Footer';
import Hero from '../sections/Hero';
import About from '../sections/About';
import Team from '../sections/Team';
import AppCon from '../sections/Contact';

const Layout = () => {
  // State untuk mengontrol visibilitas Contact
  const [isContactVisible, setIsContactVisible] = useState(false);

  return (
    <div className="min-h-screen">
      <Header />
      <main className='py-10'>
        <Hero />
        <About />
        {/* Kirim fungsi untuk menampilkan kontak ke komponen Team */}
        <Team onShowContact={() => setIsContactVisible(true)} />
        
        {/* Kontak hanya muncul jika isContactVisible bernilai true */}
        <AnimatePresence>
          {isContactVisible && (
            <AppCon />
          )}
        </AnimatePresence>
      </main>
      <Footer />
    </div>
  );
};

export default Layout;